// ─────────────────────────────────────────────
//  FIREBASE SDK LOADER
// ─────────────────────────────────────────────
let firebaseApp = null, firebaseDB = null, firebaseAuth = null;
let firebaseReady = false;

async function initFirebase() {
  if (firebaseReady) return true;
  if (!FIREBASE_CONFIGURED) return false;
  try {
    const { initializeApp } = await import("https://www.gstatic.com/firebasejs/10.12.0/firebase-app.js");
    const { getDatabase, ref, set, onValue, off } = await import("https://www.gstatic.com/firebasejs/10.12.0/firebase-database.js");
    const { getAuth, GoogleAuthProvider, signInWithPopup, signOut, onAuthStateChanged } = await import("https://www.gstatic.com/firebasejs/10.12.0/firebase-auth.js");
    firebaseApp = initializeApp(FIREBASE_CONFIG);
    firebaseDB = { db: getDatabase(firebaseApp), ref, set, onValue, off };
    firebaseAuth = { auth: getAuth(firebaseApp), GoogleAuthProvider, signInWithPopup, signOut, onAuthStateChanged };
    firebaseReady = true;
    return true;
  } catch (e) {
    console.warn("Firebase init failed:", e);
    return false;
  }
}

// ─────────────────────────────────────────────
//  UTILITY HOOKS
// ─────────────────────────────────────────────
function useAuth() {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [fbReady, setFbReady] = useState(false);

  useEffect(() => {
    initFirebase().then(ok => {
      setFbReady(ok);
      if (ok && firebaseAuth) {
        const unsub = firebaseAuth.onAuthStateChanged(firebaseAuth.auth, u => {
          setUser(u);
          setLoading(false);
        });
        return () => unsub();
      } else {
        setLoading(false);
      }
    });
  }, []);

  const loginGoogle = async () => {
    if (!firebaseAuth) return;
    const provider = new firebaseAuth.GoogleAuthProvider();
    try { await firebaseAuth.signInWithPopup(firebaseAuth.auth, provider); } catch (e) { alert("Login gagal: "+e.message); }
  };

  const logout = async () => {
    if (!firebaseAuth) return;
    try { await firebaseAuth.signOut(firebaseAuth.auth); } catch {}
  };

  return { user, loading, fbReady, loginGoogle, logout };
}

function useDB(user) {
  const [db, setDB] = useState(() => {
    try {
      const saved = localStorage.getItem("gwg_db_v2");
      return saved ? JSON.parse(saved) : DB_EMPTY;
    } catch { return DB_EMPTY; }
  });
  const [syncing, setSyncing] = useState(false);
  const dbRef = useRef(null);

  // Subscribe Firebase realtime jika user login
  useEffect(() => {
    if (!user || !firebaseDB) return;
    const { db: rtdb, ref, onValue, off } = firebaseDB;
    const r = ref(rtdb, `gwg_data/${user.uid}`);
    dbRef.current = r;
    setSyncing(true);
    const unsub = onValue(r, snap => {
      const val = snap.val();
      if (val) {
        const merged = { ...DB_EMPTY, ...val };
        setDB(merged);
        try { localStorage.setItem("gwg_db_v2", JSON.stringify(merged)); } catch {}
      }
      setSyncing(false);
    });
    return () => { off(r); dbRef.current = null; };
  }, [user]);

  const save = useCallback((newDB) => {
    setDB(newDB);
    try { localStorage.setItem("gwg_db_v2", JSON.stringify(newDB)); } catch {}
    // Push ke Firebase jika login
    if (user && firebaseDB && dbRef.current) {
      const { set } = firebaseDB;
      set(dbRef.current, newDB).catch(console.warn);
    }
  }, [user]);

  const addRecord = useCallback((table, record) => {
    save({ ...db, [table]: [...(db[table]||[]), record] });
  }, [db, save]);

  const updateRecord = useCallback((table, id, updated) => {
    save({ ...db, [table]: db[table].map(r => r.id === id ? { ...r, ...updated } : r) });
  }, [db, save]);

  const deleteRecord = useCallback((table, id) => {
    save({ ...db, [table]: db[table].filter(r => r.id !== id) });
  }, [db, save]);

  const updateStokToko = useCallback((tokoId, produkId, jumlah) => {
    const newDB = { ...db };
    newDB.toko = db.toko.map(t => {
      if (t.id !== tokoId) return t;
      return { ...t, [`stok_${produkId}`]: jumlah };
    });
    save(newDB);
  }, [db, save]);

  const resetDB = useCallback(() => { save(DB_EMPTY); }, [save]);

  return { db, addRecord, updateRecord, deleteRecord, resetDB, updateStokToko, save, syncing };
}

// ─────────────────────────────────────────────
//  DERIVED ANALYTICS
// ─────────────────────────────────────────────
function useAnalytics(db) {
  return useMemo(() => {
    const harga = {};
    (db.produk||[]).forEach(p => { harga[p.id] = p.harga; });

    const enrichKontrol = (db.kontrol||[]).map(k => {
      let totalRev = 0;
      let totalTerjual = 0;
      let totalStok = 0;
      (db.produk||[]).forEach(p => {
        const terjual = k[`terjual_${p.id}`] || 0;
        const stok = k[`stok_${p.id}`] || 0;
        totalRev += terjual * (p.harga || 0);
        totalTerjual += terjual;
        totalStok += stok;
      });
      let status = "⚪ Kosong";
      if (totalStok > 0) {
        if (totalTerjual === totalStok) status = "✅ Habis";
        else if (totalTerjual === 0) status = "🔴 Belum Laku";
        else status = "🟢 Laku Sebagian";
      }
      const toko = (db.toko||[]).find(t => t.id === k.tokoId);
      const rute = toko ? (db.rute||[]).find(r => r.id === toko.ruteId) : null;
      const wilayah = rute ? (db.wilayah||[]).find(w => w.id === rute.wilayahId) : null;
      return { ...k, totalRev, totalTerjual, totalStok, status, toko, rute, wilayah,
        tokoNama: toko?.nama||"?", ruteNama: rute?.nama||"?", wilayahNama: wilayah?.nama||"?",
        ruteId: rute?.id||"", wilayahId: wilayah?.id||"" };
    });

    const totalRev = enrichKontrol.reduce((s,k) => s + k.totalRev, 0);
    const tokoAktif = (db.toko||[]).filter(t => t.status==="Aktif").length;
    const labaBersih = totalRev * 0.7;

    const perWilayah = (db.wilayah||[]).map(w => {
      const rows = enrichKontrol.filter(k => k.wilayah?.id === w.id);
      return {
        ...w,
        rev: rows.reduce((s,k) => s + k.totalRev, 0),
        terjual: rows.reduce((s,k) => s + k.totalTerjual, 0),
        tokoCount: (db.toko||[]).filter(t => {
          const rute = (db.rute||[]).find(r => r.id === t.ruteId);
          return rute?.wilayahId === w.id;
        }).length,
      };
    });

    const perRute = (db.rute||[]).map(r => {
      const wil = (db.wilayah||[]).find(w => w.id === r.wilayahId);
      const rows = enrichKontrol.filter(k => k.rute?.id === r.id);
      return {
        ...r, wilayahNama: wil?.nama||"-",
        rev: rows.reduce((s,k) => s + k.totalRev, 0),
        tokoCount: (db.toko||[]).filter(t => t.ruteId === r.id).length,
      };
    });

    const produkStats = (db.produk||[]).map(p => ({
      ...p,
      terjual: enrichKontrol.reduce((s,k) => s + (k[`terjual_${p.id}`]||0), 0),
      rev: enrichKontrol.reduce((s,k) => s + (k[`terjual_${p.id}`]||0) * p.harga, 0),
    }));

    const bagiHasil = [
      { nama:"Pemilik Utama", pct:0.60, tipe:"Laba", nominal: labaBersih*0.60 },
      { nama:"Investor A",    pct:0.20, tipe:"Pendapatan", nominal: totalRev*0.20 },
      { nama:"Manajer Ops",   pct:0.10, tipe:"Laba", nominal: labaBersih*0.10 },
      { nama:"Karyawan Pool", pct:0.10, tipe:"Laba", nominal: labaBersih*0.10 },
    ];

    return { kontrol: enrichKontrol, totalRev, labaBersih, tokoAktif, perWilayah, perRute, produkStats, bagiHasil };
  }, [db]);
}

// ─────────────────────────────────────────────
