function LoginPage({ onLoginGoogle, fbReady, error }) {
  return (
    <div style={{ minHeight:"100vh", background:`linear-gradient(135deg, ${T.green} 0%, ${T.greenMid} 60%, #0A3526 100%)`,
      display:"flex", alignItems:"center", justifyContent:"center", padding:"20px" }}>
      <div style={{ background:T.white, borderRadius:20, padding:"40px 36px", maxWidth:400, width:"100%",
        boxShadow:"0 20px 60px rgba(0,0,0,.25)", textAlign:"center" }}>
        
        {/* Logo */}
        <img src={GWG_LOGO_B64} alt="GWG Logo"
          style={{ width:90, height:90, borderRadius:"50%", objectFit:"contain",
            background:T.greenLt, padding:8, marginBottom:20, border:`3px solid ${T.greenMid}` }} />

        <h1 style={{ fontSize:22, fontWeight:800, color:T.green, margin:"0 0 4px" }}>
          Generasi Wangi Group
        </h1>
        <p style={{ fontSize:13, color:T.gray400, marginBottom:32, letterSpacing:"0.06em", textTransform:"uppercase" }}>
          Super App · Manajemen Konsinyasi
        </p>

        {fbReady ? (
          <>
            <button onClick={onLoginGoogle}
              style={{ width:"100%", padding:"13px 24px", borderRadius:12, border:`1px solid ${T.gray200}`,
                background:T.white, cursor:"pointer", display:"flex", alignItems:"center", justifyContent:"center",
                gap:12, fontSize:15, fontWeight:600, color:T.gray800, fontFamily:"inherit",
                boxShadow:"0 2px 8px rgba(0,0,0,.08)", transition:"all .15s" }}
              onMouseEnter={e => { e.target.style.background=T.gray50; e.target.style.boxShadow="0 4px 16px rgba(0,0,0,.12)"; }}
              onMouseLeave={e => { e.target.style.background=T.white; e.target.style.boxShadow="0 2px 8px rgba(0,0,0,.08)"; }}>
              {/* Google icon SVG */}
              <svg width="20" height="20" viewBox="0 0 48 48">
                <path fill="#EA4335" d="M24 9.5c3.54 0 6.71 1.22 9.21 3.6l6.85-6.85C35.9 2.38 30.47 0 24 0 14.62 0 6.51 5.38 2.56 13.22l7.98 6.19C12.43 13.72 17.74 9.5 24 9.5z"/>
                <path fill="#4285F4" d="M46.98 24.55c0-1.57-.15-3.09-.38-4.55H24v9.02h12.94c-.58 2.96-2.26 5.48-4.78 7.18l7.73 6c4.51-4.18 7.09-10.36 7.09-17.65z"/>
                <path fill="#FBBC05" d="M10.53 28.59c-.48-1.45-.76-2.99-.76-4.59s.27-3.14.76-4.59l-7.98-6.19C.92 16.46 0 20.12 0 24c0 3.88.92 7.54 2.56 10.78l7.97-6.19z"/>
                <path fill="#34A853" d="M24 48c6.48 0 11.93-2.13 15.89-5.81l-7.73-6c-2.18 1.48-4.97 2.35-8.16 2.35-6.26 0-11.57-4.22-13.47-9.91l-7.98 6.19C6.51 42.62 14.62 48 24 48z"/>
              </svg>
              Masuk dengan Google
            </button>

            {error && (
              <div style={{ marginTop:16, padding:"10px 16px", background:T.redLt, borderRadius:8,
                fontSize:13, color:T.red, border:`1px solid #FCA5A5` }}>
                ⚠️ {error}
              </div>
            )}

            <p style={{ fontSize:12, color:T.gray400, marginTop:20 }}>
              Hanya akun Google yang terdaftar dapat mengakses aplikasi ini.
            </p>
          </>
        ) : (
          <div style={{ padding:"20px 0" }}>
            <div style={{ width:40, height:40, border:`3px solid ${T.green}`, borderTopColor:"transparent",
              borderRadius:"50%", margin:"0 auto 16px", animation:"spin 1s linear infinite" }} />
            <p style={{ color:T.gray600, fontSize:14 }}>Memuat sistem autentikasi...</p>
            <p style={{ color:T.red, fontSize:12, marginTop:8 }}>
              Pastikan FIREBASE_CONFIG sudah dikonfigurasi di source code.
            </p>
          </div>
        )}

        <div style={{ marginTop:32, paddingTop:20, borderTop:`1px solid ${T.gray100}`,
          fontSize:11, color:T.gray400 }}>
          © {new Date().getFullYear()} Generasi Wangi Group · Sampang, Jawa Timur
        </div>
      </div>
      <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
    </div>
  );
}

const TABS = [
  { key:"dashboard", label:"📈 Dashboard" },
  { key:"wilayah",   label:"📍 Wilayah" },
  { key:"rute",      label:"🛣️ Rute" },
  { key:"toko",      label:"🏪 Toko" },
  { key:"produk",    label:"🧴 Produk" },
  { key:"kontrol",   label:"📋 Kontrol" },
  { key:"rekap",     label:"📑 Rekap" },
  { key:"pengguna",  label:"👤 Pengguna" },
];

export default function GWGSuperApp() {
  const [activeTab, setActiveTab] = useState("dashboard");
  const [showReset, setShowReset] = useState(false);
  const [loginError, setLoginError] = useState("");
  const { user, loading, fbReady, loginGoogle, logout } = useAuth();
  const { db, addRecord, updateRecord, deleteRecord, resetDB, save, syncing } = useDB(user);
  const analytics = useAnalytics(db);

  // Cari role user yang login berdasarkan email di tabel pengguna
  const currentUserRecord = user ? db.pengguna.find(p => p.email?.toLowerCase() === user.email?.toLowerCase()) : null;
  const userRole = currentUserRecord?.role || "Sales"; // default Sales jika tidak ditemukan
  const isAdmin = userRole === "Admin";
  const isManajer = userRole === "Manajer" || isAdmin;

  const handleLoginGoogle = async () => {
    setLoginError("");
    try {
      await loginGoogle();
    } catch(e) {
      setLoginError(e.message || "Login gagal");
    }
  };

  if (loading) {
    return (
      <div style={{ minHeight:"100vh", background:T.bg, display:"flex", alignItems:"center", justifyContent:"center", flexDirection:"column", gap:16 }}>
        <img src={GWG_LOGO_B64} alt="GWG" style={{ width:64, height:64, borderRadius:"50%", objectFit:"contain", background:"#fff", padding:6, boxShadow:"0 4px 16px rgba(0,0,0,.1)" }} />
        <div style={{ fontSize:16, color:T.gray600, fontWeight:600 }}>Memuat Generasi Wangi Group...</div>
      </div>
    );
  }

  // Jika Firebase dikonfigurasi tapi user belum login → tampilkan halaman login
  if (FIREBASE_CONFIGURED && !user) {
    return <LoginPage onLoginGoogle={handleLoginGoogle} fbReady={fbReady} error={loginError} />;
  }

  return (
    <div style={{ minHeight:"100vh", background:T.bg, fontFamily:"'Inter',system-ui,sans-serif" }}>
      {/* HEADER */}
      <div style={{ background:`linear-gradient(135deg, ${T.green} 0%, ${T.greenMid} 100%)`, boxShadow:"0 2px 12px rgba(0,0,0,.15)" }}>
        <div style={{ maxWidth:1400, margin:"0 auto", padding:"0 20px" }}>
          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", paddingTop:16, paddingBottom:16 }}>
            <div style={{ display:"flex", alignItems:"center", gap:14 }}>
              <img src={GWG_LOGO_B64} alt="GWG Logo"
                style={{ width:46, height:46, borderRadius:"50%", background:"#fff",
                  padding:3, boxShadow:"0 2px 8px rgba(0,0,0,.2)", objectFit:"contain" }} />
              <div>
                <div style={{ fontSize:20, fontWeight:800, color:"#fff", letterSpacing:"-0.02em" }}>Generasi Wangi Group</div>
                <div style={{ fontSize:11, color:"rgba(255,255,255,.7)", letterSpacing:"0.08em", textTransform:"uppercase" }}>
                  Super App · Sistem Manajemen Konsinyasi
                  {syncing && <span style={{ marginLeft:8, background:"rgba(255,255,255,.2)", borderRadius:99, padding:"1px 8px", fontSize:10 }}>🔄 Sinkronisasi...</span>}
                </div>
              </div>
            </div>
            <div style={{ display:"flex", alignItems:"center", gap:10 }}>
              <div style={{ background:"rgba(255,255,255,.12)", borderRadius:10, padding:"6px 14px", fontSize:12, color:"rgba(255,255,255,.9)", fontWeight:600 }}>
                💰 Rev: {fmtRp(analytics.totalRev)}
              </div>

              {/* User section */}
              {fbReady ? (
                user ? (
                  <div style={{ display:"flex", alignItems:"center", gap:8 }}>
                    {user.photoURL && (
                      <img src={user.photoURL} alt="" style={{ width:30, height:30, borderRadius:"50%", border:"2px solid rgba(255,255,255,.4)" }} />
                    )}
                    <div style={{ fontSize:12, color:"rgba(255,255,255,.9)", fontWeight:600 }}>
                      {user.displayName?.split(" ")[0]}
                      <div style={{ fontSize:10, color:"rgba(255,255,255,.6)", fontWeight:400 }}>
                        ☁️ {syncing ? "Sinkronisasi..." : "Sinkron aktif"} ·{" "}
                        <span style={{ background:"rgba(255,255,255,.2)", borderRadius:4, padding:"0 5px", fontWeight:700 }}>
                          {userRole}
                        </span>
                      </div>
                    </div>
                    <Btn variant="secondary" size="sm" onClick={logout}
                      style={{ background:"rgba(255,255,255,.1)", color:"#fff", border:"1px solid rgba(255,255,255,.2)" }}>
                      Keluar
                    </Btn>
                  </div>
                ) : (
                  <Btn variant="secondary" size="sm" onClick={loginGoogle}
                    style={{ background:"rgba(255,255,255,.15)", color:"#fff", border:"1px solid rgba(255,255,255,.3)" }}>
                    <span style={{ fontSize:14 }}>G</span> Login Google
                  </Btn>
                )
              ) : (
                <div style={{ fontSize:11, color:"rgba(255,255,255,.5)", padding:"6px 10px", background:"rgba(255,255,255,.08)", borderRadius:8 }}>
                  💾 Mode Lokal
                </div>
              )}

              <Btn variant="secondary" size="sm" onClick={()=>setShowReset(true)}
                style={{ background:"rgba(255,255,255,.1)", color:"#fff", border:"1px solid rgba(255,255,255,.2)" }}>
                ⚙️ Reset
              </Btn>
            </div>
          </div>

          {/* Sync status banner jika Firebase belum dikonfigurasi */}
          {!FIREBASE_CONFIGURED && (
            <div style={{ background:"rgba(196,154,26,.25)", border:"1px solid rgba(196,154,26,.4)", borderRadius:8, padding:"8px 14px",
              marginBottom:12, fontSize:12, color:"#FBF3D9", display:"flex", alignItems:"center", gap:8 }}>
              ⚠️ <span><b>Mode Lokal:</b> Untuk sinkronisasi lintas perangkat, konfigurasikan Firebase di variabel <code>FIREBASE_CONFIG</code> pada file ini. Lihat instruksi di komentar atas.</span>
            </div>
          )}

          <div style={{ display:"flex", gap:2, overflowX:"auto", paddingBottom:0 }}>
            {TABS.filter(t => t.key !== "pengguna" || isAdmin).map(t=>(
              <button key={t.key} onClick={()=>setActiveTab(t.key)}
                style={{ padding:"10px 18px", border:"none", cursor:"pointer", fontFamily:"inherit",
                  fontWeight:600, fontSize:13, whiteSpace:"nowrap", borderRadius:"10px 10px 0 0", transition:"all .15s",
                  background:activeTab===t.key?T.white:"transparent",
                  color:activeTab===t.key?T.green:"rgba(255,255,255,.75)" }}>
                {t.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* CONTENT */}
      <div style={{ maxWidth:1400, margin:"0 auto", padding:"24px 20px" }}>
        {activeTab==="dashboard" && <Dashboard db={db} analytics={analytics} />}
        {activeTab==="wilayah"   && <TabWilayah   db={db} addRecord={addRecord} updateRecord={updateRecord} deleteRecord={deleteRecord} />}
        {activeTab==="rute"      && <TabRute      db={db} addRecord={addRecord} updateRecord={updateRecord} deleteRecord={deleteRecord} />}
        {activeTab==="toko"      && <TabToko      db={db} addRecord={addRecord} updateRecord={updateRecord} deleteRecord={deleteRecord} save={save} />}
        {activeTab==="produk"    && <TabProduk    db={db} addRecord={addRecord} updateRecord={updateRecord} deleteRecord={deleteRecord} />}
        {activeTab==="kontrol"   && <TabKontrol   db={db} addRecord={addRecord} updateRecord={updateRecord} deleteRecord={deleteRecord} save={save} />}
        {activeTab==="rekap"     && <TabRekap     db={db} analytics={analytics} />}
        {activeTab==="pengguna"  && <TabPengguna  db={db} addRecord={addRecord} updateRecord={updateRecord} deleteRecord={deleteRecord} />}
      </div>

      {/* RESET CONFIRM */}
      {showReset && (
        <Modal title="⚠️ Reset Database" onClose={()=>setShowReset(false)}>
          <div style={{ textAlign:"center", padding:"8px 0 20px" }}>
            <div style={{ fontSize:40, marginBottom:12 }}>⚠️</div>
            <div style={{ fontSize:15, fontWeight:600, color:T.gray800, marginBottom:8 }}>Reset semua data ke kosong?</div>
            <div style={{ fontSize:13, color:T.gray400, marginBottom:20 }}>
              Semua data yang sudah diinput akan <b>hilang permanen</b>. Tindakan ini tidak bisa dibatalkan.
              {user && <div style={{ marginTop:8, color:T.red }}><b>⚠️ Data di cloud (Firebase) juga akan dihapus!</b></div>}
            </div>
            <div style={{ display:"flex", gap:10, justifyContent:"center" }}>
              <Btn variant="secondary" onClick={()=>setShowReset(false)}>Batal</Btn>
              <Btn variant="danger" onClick={()=>{ resetDB(); setShowReset(false); }}>Ya, Reset Sekarang</Btn>
            </div>
          </div>
        </Modal>
      )}
    </div>
  );
}
